import React, { useId } from 'react'

interface EnvelopeIconProps extends React.ComponentProps<'div'> {
  className?: string
}

const EnvelopeIcon = ({ className, ...props }: EnvelopeIconProps) => {
  const uniqueId = useId()
  const svgContent = `<svg width="224" height="172" viewBox="0 0 224 172" fill="none" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
<rect width="223.666" height="171.453" fill="url(#pattern0_8322_16574)"/>
<defs>
<pattern id="pattern0_8322_16574" patternContentUnits="objectBoundingBox" width="1" height="1">
<use xlink:href="#image0_8322_16574" transform="matrix(0.000976562 0 0 0.00127396 0 -0.152266)"/>
</pattern>
<image id="image0_8322_16574" width="1024" height="1024" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
</defs>
</svg>
`
  const svgWithUniqueIds = svgContent
    .replace(/pattern0_8322_16574/g, `pattern_${uniqueId}`)
    .replace(/image0_8322_16574/g, `image_${uniqueId}`)

  return (
    <div
      className={className}
      dangerouslySetInnerHTML={{ __html: svgWithUniqueIds }}
      {...props}
    />
  )
}

export { EnvelopeIcon }
